INSERT INTO `renewal_recommendations` VALUES (5,23,1,'1-2526',4.63,5.00,4.33,10,0,1.40,3.40,0.00,'Recommended','The faculty has demonstrated VERY SATISFACTORY performance with an overall weighted score of 4.63 out of 5.0. For Contract of Service (COS) Faculty: Instruction Average: 5 (OUTSTANDING) - Weighted at 90%. Support Function Average: 4.33 (VERY SATISFACTORY) - Weighted at 10%. A total of 10 rating(s) were submitted for evaluation. Based on the satisfactory performance indicators, this faculty member is RECOMMENDED for contract renewal.',NULL,'Pending',NULL,'2026-04-15 07:09:16','2026-04-15 07:09:16'),(6,25,1,'1-2526',3.65,2.00,5.00,6,0,0.83,4.00,0.00,'Recommended','The faculty has demonstrated VERY SATISFACTORY performance with an overall weighted score of 3.65 out of 5.0. For Contract of Service (COS) Faculty: Instruction Average: 2 (UNSATISFACTORY) - Weighted at 90%. Support Function Average: 5 (OUTSTANDING) - Weighted at 10%. A total of 6 rating(s) were submitted for evaluation. Based on the satisfactory performance indicators, this faculty member is RECOMMENDED for contract renewal.',NULL,'Pending',NULL,'2026-04-15 07:09:24','2026-04-15 07:09:24'),(7,30,1,'1-2526',4.55,4.42,4.67,10,0,1.40,3.30,0.00,'Recommended','The faculty has demonstrated VERY SATISFACTORY performance with an overall weighted score of 4.55 out of 5.0. For Contract of Service (COS) Faculty: Instruction Average: 4.42 (VERY SATISFACTORY) - Weighted at 90%. Support Function Average: 4.67 (VERY SATISFACTORY) - Weighted at 10%. A total of 10 rating(s) were submitted for evaluation. Based on the satisfactory performance indicators, this faculty member is RECOMMENDED for contract renewal.',NULL,'Pending',NULL,'2026-04-15 07:50:10','2026-04-15 07:50:10'),(8,32,1,'1-2526',4.52,4.76,4.33,10,0,1.49,3.10,0.00,'Recommended','The faculty has demonstrated VERY SATISFACTORY performance with an overall weighted score of 4.52 out of 5.0. For Contract of Service (COS) Faculty: Instruction Average: 4.76 (OUTSTANDING) - Weighted at 90%. Support Function Average: 4.33 (VERY SATISFACTORY) - Weighted at 10%. A total of 10 rating(s) were submitted for evaluation. Based on the satisfactory performance indicators, this faculty member is RECOMMENDED for contract renewal.',NULL,'Pending',NULL,'2026-04-16 20:09:07','2026-04-16 20:09:07'),(9,31,1,'1-2526',0.30,0.33,0.00,1,0,4.00,0.00,0.00,'Not Recommended','The faculty has demonstrated POOR performance with an overall weighted score of 0.30 out of 5.0. For Contract of Service (COS) Faculty: Instruction Average: 0.33 (POOR) - Weighted at 90%. A total of 1 rating(s) were submitted for evaluation. Based on the poor performance indicators, this faculty member is NOT RECOMMENDED for contract renewal at this time.',NULL,'Pending',NULL,'2026-04-17 15:48:13','2026-04-17 15:48:13');
