INSERT INTO `task_list` VALUES (1,1,0,0,'core','ter',NULL,'Teaching Effectiveness  ','Obtain a rating in the teaching effectiveness during the rating period','','','Applicable',1,NULL,'2025-10-30 21:07:55','2026-04-02 13:07:17'),(2,1,0,0,'core','instructions',NULL,'Attendance to Classes','Percentage of classes attended (outside of attendance not covered by deloading or designation must be supported of evidence of make up class or advanced classes)\r\n\r\nEFFICIENCY: \r\n5 - 91% to 100%,\r\n4 - 86% to 90%,\r\n3 - 80%-85%,\r\n2 - 51-79%,\r\n1 -  50 and below\r\n','','','Applicable',1,NULL,'2025-10-30 21:10:48','2026-03-30 16:51:29'),(3,1,0,0,'core','instructions',NULL,'Timeliness in submission of Test Questions and Table of Specification ','Timeliness:\n5 - 5 working days before the exam,\n4 - 4 working days before the exam,\n3 - 3 working days before the exam,\n2 - 1-2 working days before the exam,\n1 -  on the day of exam\n','','Applicable','',1,NULL,'2025-10-30 21:13:06','2026-04-04 23:27:48'),(4,1,0,0,'core','instructions',NULL,'Timeliness of Syllabi Submission ','Timeliness:\r\n5 - 1 week after the start of classes,\r\n4  - ,	\r\n3 - 2 weeks after the start of classes,\r\n2 - 3 weeks after the start of classes,\r\n1 - 4 weeks or more days after the start of classes\r\n','','Applicable','',1,NULL,'2025-10-30 21:14:17','2026-03-30 16:50:55'),(5,1,0,0,'core','instructions',NULL,'Timeliness of Course Outline Distribution to Students  ','Timeliness:\r\n5 - Within the 1st week  of classes,\r\n4 - ,\r\n3 - Within the 2nd week  of classes,\r\n2 - Within the Semester,\r\n1 - None\r\n','','Applicable','',1,NULL,'2025-10-30 21:15:08','2026-03-30 16:50:47'),(6,1,0,0,'core','instructions',NULL,'Timeliness in returning of outputs (Midterm Exam only)','Timeliness:\r\n5 - Within the semester,\r\n4 - \r\n3 - \r\n2 - After the semester,\r\n1 - None\r\n','','Applicable','',1,NULL,'2025-10-30 21:15:57','2026-03-30 16:50:35'),(7,1,0,0,'core','instructions',NULL,'Timeliness of Grade Submission ( 10 WDs after the final exam)','Timeliness:\r\n5 - 1-7 days after the Final Exam,\r\n4 - 8-9 days after the Final Exam,\r\n3 - 10 days after the Final Exam,\r\n2 - 11 to 15 days after the final Exam,\r\n1 - 16 days or more\r\n','','Applicable','',1,NULL,'2025-10-30 21:16:41','2026-03-30 16:48:30'),(11,2,0,0,'core','instructions',NULL,'Development of  Instructional Materials  every end of the rating period----per commitment only','Quality\r\n5	Approved for implementation by the Academic Council\r\n4	Approved by IM Committee\r\n3	Approved by College IM Committee\r\n2	Approved by Department IM Committee\r\n1	Not reviewed\r\n','Applicable','','',1,NULL,'2025-10-30 21:31:33','2026-03-30 16:47:37'),(12,3,0,0,'core','research',NULL,'Research Engagement and Productivity ','At least 1 completed research by a faculty (or more authors) during the rating period.\r\n\r\nQuality ,\r\n5	Approved completed research\r\n4	Research Performance Reviewed\r\n3	Research implemented\r\n2	Approved Research proposal in the review committee\r\n1	 None submitted\r\n\r\nEFFICIENCY\r\nE	% of CONTRIBUTION\r\n5	60% and above total contribution\r\n4	40-59%\r\n3	30-39%\r\n2	11-29%\r\n1	1-10%\r\n','Applicable','','Applicable',1,NULL,'2025-10-30 21:36:12','2026-03-30 16:47:25'),(13,2,0,0,'core','research',NULL,'Research published in reputable journal','At least 1 published research by a faculty during the rating period.\r\n\r\nQuality:\r\n5	Published or accepted in Scopus/WoS/ACI \r\n4	Published or accepted in a university journal \r\n3	With results of peer-review by a reputable journal \r\n2	Submitted and acknowledge\r\n1	 No published research\r\n\r\n','Applicable','','',1,NULL,'2025-10-30 21:37:16','2026-03-30 16:47:15'),(14,2,0,0,'core','research',NULL,'Research presented in International and Local Fora','At least 1 completed research presented by faculty in the  during the rating period. Note: Approved by the R&D as completed research. Only the presenter will earn points.\r\nQuality \r\n5	Presented International\r\n4	Presented National and Regional\r\n3	Presented Regional\r\n2	Presented in In-House\r\n1	No presentation\r\n','Applicable','','',1,NULL,'2025-10-30 21:37:42','2026-03-30 16:47:00'),(15,4,0,0,'core','extension',NULL,'Extension Services Engagement (Research-Based)','At least 1 research-based extension service for the rating period. Can be done in group, rating will be the same to all extensionist involved.\r\n\r\nQuality \r\n5	With approved extension terminal report\r\n4	With reviewed extension terminal report\r\n3	Extension Program implemented\r\n2	Approved Extension Proposal\r\n1	None submitted\r\n','Applicable','','',1,NULL,'2025-10-30 21:42:20','2026-03-30 16:46:52'),(16,4,0,0,'core','extension',NULL,'Community Outreach Engagement (Technical Advisory Services requested): ','At least 1 community outreach for the rating period. Can be done in group, rating will be the same to all extensionist involved\r\nQuality \r\n5	With approved community outreach terminal report\r\n4	With reviewed community outreach terminal report\r\n3	Community Outreach Program implemented\r\n2	Approved community outreach  Proposal\r\n1	None submitted\r\n','Applicable','','',1,NULL,'2025-10-30 21:43:18','2026-03-30 16:46:41'),(17,4,0,0,'core','extension',NULL,'Percentage of persons trained weighted by the length of training per program ','( Percentage = Number clients served/ total number of target)\r\nEfficiency \r\n5	90%-100%\r\n4	80%-89%\r\n3	75%-79%\r\n2	70%-74%\r\n1	69% and below\r\n','','','Applicable',1,NULL,'2025-10-30 21:44:00','2026-03-30 16:46:20'),(18,2,0,0,'support',NULL,NULL,'Timely Submission of duly notarized SALN and PDS deadline is every 31st day of March.','Timeliness\r\n5	before the deadline\r\n4	\r\n3	On the deadline\r\n2	Beyond the deadline\r\n1	No Submission\r\n','','Applicable','',1,NULL,'2025-10-30 21:44:30','2026-03-30 16:37:26'),(22,0,0,0,'support',NULL,NULL,'Timely Submission of DTR  with complete attachments ','Deadline is every 15th of the ensuing month\nTimeliness\n5	before the deadline\n4	\n3	On the deadline\n2	Beyond the deadline\n1	No Submission\n','','Applicable','',1,NULL,'2025-10-30 22:29:04','2026-04-04 16:59:13'),(23,0,0,0,'support',NULL,NULL,'Percentage of attendance to College Wide Activities','(Charter Day, Sports events, Year end activity, Council Meetings (applicable to Asst Prof to Prof), Graduation Ceremony\r\nEfficiency\r\n5	100%\r\n4	75% to 99%\r\n3	63% to 74%\r\n2	51% to 62%\r\n1	Below 50%\r\n','','','Applicable',1,NULL,'2025-10-30 22:29:28','2026-03-30 16:33:36'),(24,0,0,0,'support',NULL,NULL,'Timeliness in submission of quarterly accomplishment report','Every 15th of January, April, July and October\r\nTimeliness\r\n5	before the deadline\r\n4	\r\n3	On the deadline\r\n2	Beyond the deadline\r\n1	No Submission\r\n','','Applicable','',1,NULL,'2025-10-30 22:29:57','2026-03-30 16:33:27'),(26,0,2,0,'strategic','',NULL,'53% of graduates in the program (2 years prior) are employed','EFFICIENCY\r\n5	69% and above\r\n4	61% to 68%\r\n3	 53%-60%\r\n2	 27% to 52.%\r\n1	26% and below\r\n','','','Applicable',1,NULL,'2026-03-30 16:54:45','2026-03-30 16:54:45'),(27,0,2,0,'strategic','',NULL,'100% of students in the program underwent admission and classification process','EFFICIENCY\r\n5	100%\r\n4	90-99%\r\n3	80-89%\r\n2	70-79%\r\n1	69% and below\r\n','','','Applicable',1,NULL,'2026-03-30 16:55:03','2026-03-30 16:55:03'),(28,0,2,0,'strategic','',NULL,'Submitted report on the appraisal /evaluation conducted to assigned faculty of the department  before the start of the next semester','EFFICIENCY\r\n5	100% of faculty\r\n4	90-99%\r\n3	80-89%\r\n2	70-79%\r\n1	69% and below\r\n','','','Applicable',1,NULL,'2026-03-30 16:55:30','2026-03-30 16:55:30'),(29,0,2,0,'strategic','',NULL,'Facilitate the conduct of Student evaluation (within the program)  at the end of academic year','QUALITY\r\n5	Student evaluation conducted with complete reports\r\n4	-\r\n3	Student evaluation conducted \r\n2	-\r\n1	None\r\n','Applicable','','',1,NULL,'2026-03-30 16:55:54','2026-03-30 16:55:54'),(30,0,2,0,'strategic','',NULL,'Conducted at least one per semester Class Monitoring of ALL assigned faculty (Regular and COS) using Class/Faculty Observation form','EFFICIENCY\r\n5	100% of faculty for  2 semesters\r\n4	90-99%\r\n3	80-89%\r\n2	70-79%\r\n1	69% and below\r\n','','','Applicable',1,NULL,'2026-03-30 16:56:22','2026-03-30 16:56:22'),(31,0,2,0,'strategic','',NULL,'Conducted PMC and Submitted at least 3 PMC Report within the rating period','EFFICIENCY\r\n5 - 5\r\n4 - 4\r\n3 - 3\r\n2 - 1-2\r\n1 - None\r\n','','','Applicable',1,NULL,'2026-03-30 16:57:32','2026-03-30 16:57:32'),(32,0,6,0,'strategic','',NULL,'1 Institutional Policy to support','','Applicable','','',1,NULL,'2026-04-09 23:28:59','2026-04-09 23:28:59'),(33,0,6,0,'strategic','',NULL,'Extension Services	100% Utilization rate of allocated funds for extension services during the period covered (GAA Fund)					Cert from Budget Office','','Applicable','','',1,NULL,'2026-04-09 23:29:17','2026-04-09 23:29:17'),(34,0,6,0,'strategic','',NULL,'100% Utilization rate of direct internally generated incomes (IGI) / Grants-in-aid (GIA)','','','','Applicable',1,NULL,'2026-04-09 23:29:39','2026-04-09 23:29:39'),(35,0,6,0,'strategic','',NULL,'60% of plantilla faculty and staff involved in ESCE within the period covered','','','','Applicable',1,NULL,'2026-04-09 23:30:05','2026-04-09 23:30:05'),(36,0,6,0,'strategic','',NULL,'60% of students involved in ESCE enrolled in programs with extension courses within the period covered','','','','Applicable',1,NULL,'2026-04-09 23:30:21','2026-04-09 23:30:21'),(37,0,6,0,'strategic','',NULL,'','18 active partnerships with LGUs, industries, NGOs, NGAs, SMEs, and other stakeholders as a result of extension activities.','Applicable','','',1,NULL,'2026-04-09 23:30:39','2026-04-09 23:30:39');
